    // The possible optimal thresholds are 0 and all existing edge weights.
    let mut unique_weights_set = std::collections::HashSet::new();
    unique_weights_set.insert(0);
    for edge in &edges {
        let w = edge[2];
        unique_weights_set.insert(w);
    }
    let mut sorted_weights: Vec<i64> = unique_weights_set.into_iter().collect();
    sorted_weights.sort_unstable();

    // Adjacency list representation of the graph: (neighbor, weight)
    let mut adj: Vec<Vec<(i64, i64)>> = vec![vec![]; n as usize];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        adj[u].push((v as i64, w));
        adj[v].push((u as i64, w));
    }

    // Checks if there is a path from source to target using at most k heavy edges,
    // given a specific threshold.
    let check = |threshold: i64| -> bool {
        // dist[i][j] = minimum number of edges (or just boolean reachability) to reach node i 
        // using exactly j heavy edges.
        // Since we only care about reachability within K heavy edges, we use BFS on the state space (node, heavy_count).

        // State: (node, heavy_count)
        // visited[node][heavy_count] = true if this state has been reached.
        let mut visited: Vec<Vec<bool>> = vec![vec![false; (k + 1) as usize]; n as usize];
        let mut queue: VecDeque<(i64, i64)> = VecDeque::new();

        // Start state: (source, 0 heavy edges)
        queue.push_back((source, 0));
        visited[source as usize][0] = true;

        while let Some((u, count)) = queue.pop_front() {
            if u == target {
                return true;
            }

            for &(v_i64, w) in &adj[u as usize] {
                // Determine if the edge (u, v) is heavy
                let is_heavy = if w > threshold { 1 } else { 0 };
                let new_count = count + is_heavy;

                if new_count <= k {
                    let v = v_i64;
                    if !visited[v as usize][new_count as usize] {
                        visited[v as usize][new_count as usize] = true;
                        queue.push_back((v, new_count));
                    }
                }
            }
        }

        false
    };

    // Iterate through sorted unique weights (potential thresholds). The first one that works is the minimum.
    for &threshold in &sorted_weights {
        if check(threshold) {
            return threshold;
        }
    }

    // If no threshold worked, check if any path exists even if all edges are considered light (i.e., check with max weight).
    // If check(max_weight) fails, it implies no path exists that satisfies the constraint for any threshold, 
    // because if a path exists, it must be reachable under the condition where all edges are light (weight <= max_weight), 
    // which means it uses 0 heavy edges.

    // Since we iterate up to the largest weight, if we exit the loop, no threshold worked.
    // We must confirm the "no path exists" case.

    // If check(sorted_weights.last().unwrap()) is false, then no path exists with <= k heavy edges, 
    // because that threshold makes all edges light (0 heavy edges).
    if let Some(&max_w) = sorted_weights.last() {
        if !check(max_w) {
            return -1;
        }
    } else {
        // This case should not happen if edges.len() >= 0 and unique_weights_set includes 0.
        return -1; 
    }

    // Should be unreachable if logic is sound, but return -1 as fallback.
    -1
}
